import math

# Geometric manipulation detection
def detect_geometric_distortion(claimed_values, measured_values):
    """Detect geometric distortions in data presentation."""
    if len(claimed_values) != len(measured_values):
        return {"error": "Mismatched dimensions"}

    distortions = []
    for i, (c, m) in enumerate(zip(claimed_values, measured_values)):
        if m > 0:
            ratio = c / m
            if abs(ratio - 1.0) > 0.1:  # 10% threshold
                distortions.append({
                    "dimension": i,
                    "claimed": c,
                    "measured": m,
                    "distortion_ratio": round(ratio, 3)
                })

    return {
        "distortion_count": len(distortions),
        "distortions": distortions,
        "integrity": "concern" if len(distortions) > 2 else
                     "notice" if len(distortions) > 0 else "healthy"
    }

result = detect_geometric_distortion(
    claimed_values=[1.0, 2.0, 3.0, 4.0],
    measured_values=[1.0, 1.5, 3.0, 6.0]
)
print(result)
